import{_ as t,o as e,c as d,a2 as n}from"./chunks/framework.BFVZdVmd.js";const u=JSON.parse('{"title":"Java 基础","description":"","frontmatter":{},"headers":[],"relativePath":"java-core/index.md","filePath":"java-core/index.md","lastUpdated":null}'),r={name:"java-core/index.md"};function o(l,a,s,i,c,h){return e(),d("div",null,[...a[0]||(a[0]=[n(`<h1 id="java-基础" tabindex="-1">Java 基础 <a class="header-anchor" href="#java-基础" aria-label="Permalink to &quot;Java 基础&quot;">​</a></h1><blockquote><p>本栏目为知识库新增内容，不属于《Spring 技术套件》原文档。它补齐企业 Java 后端开发的语言与运行时根基——这是微服务技术栈的前提，却常被「技术栈地图」类资料默认跳过。</p></blockquote><p>Spring Cloud 的每一个微服务，本质上都是一个跑在 JVM 上的 Java 应用。框架解决的是「服务怎么治理」，而语言、运行时和并发能力决定的是「单个服务能不能写对、跑稳、查得了问题」。线上排查的很多疑难（内存溢出、CPU 飙高、线程死锁、GC 停顿），最终都要落到这一层。</p><h2 id="本栏目内容" tabindex="-1">本栏目内容 <a class="header-anchor" href="#本栏目内容" aria-label="Permalink to &quot;本栏目内容&quot;">​</a></h2><ul><li><a href="./language">语言核心</a>：集合、泛型、异常、IO/NIO、注解与反射，以及 Java 8+ 的关键特性。</li><li><a href="./jvm">JVM</a>：内存结构、垃圾回收、类加载机制，以及线上内存与性能问题排查。</li><li><a href="./concurrency">并发编程</a>：线程、内存可见性、JUC 工具集、线程池与锁原理。</li></ul><h2 id="知识地图" tabindex="-1">知识地图 <a class="header-anchor" href="#知识地图" aria-label="Permalink to &quot;知识地图&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>关键点</th><th>为什么重要</th></tr></thead><tbody><tr><td>语言核心</td><td>集合框架、泛型、异常体系、Stream / Lambda、反射</td><td>日常写业务代码的基本功，也是框架底层原理的基础</td></tr><tr><td>JVM</td><td>运行时内存、GC、类加载、调优</td><td>线上 OOM、Full GC、内存泄漏排查的根基</td></tr><tr><td>并发</td><td>线程模型、<code>synchronized</code>/<code>volatile</code>、线程池、<code>JUC</code></td><td>高并发接口、异步任务、数据一致性的关键</td></tr></tbody></table><h2 id="建议学习顺序" tabindex="-1">建议学习顺序 <a class="header-anchor" href="#建议学习顺序" aria-label="Permalink to &quot;建议学习顺序&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>语言核心（先能写对）</span></span>
<span class="line"><span>  -&gt; 并发编程（再能扛住高并发）</span></span>
<span class="line"><span>  -&gt; JVM（最后能调优和排障）</span></span></code></pre></div><p>新手优先打牢语言核心；有一定经验后，并发和 JVM 是从「会写」到「写好」的分水岭，也是面试和线上排障的高频区。</p>`,10)])])}const b=t(r,[["render",o]]);export{u as __pageData,b as default};
